{"language": "html", "code": "<!DOCTYPE html>
<html lang="zh">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Graduation Trip · California 2026</title>
<link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/@tabler/icons-webfont@2.44.0/tabler-icons.min.css">
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  :root {
    --bg: #f7f6f3;
    --surface: #ffffff;
    --surface2: #f1efeb;
    --border: rgba(0,0,0,0.1);
    --border2: rgba(0,0,0,0.18);
    --text: #1a1a18;
    --text2: #6b6b67;
    --text3: #a0a09c;
    --accent: #4a6fa5;
    --accent-bg: #e8eef7;
    --green: #3b6d11;
    --green-bg: #eaf3de;
    --amber: #854f0b;
    --amber-bg: #faeeda;
    --red: #a32d2d;
    --red-bg: #fcebeb;
    --purple: #534ab7;
    --purple-bg: #eeedfe;
    --teal: #0f6e56;
    --teal-bg: #e1f5ee;
    --radius: 8px;
    --radius-lg: 12px;
  }
  @media (prefers-color-scheme: dark) {
    :root {
      --bg: #1a1a18;
      --surface: #242422;
      --surface2: #2e2e2b;
      --border: rgba(255,255,255,0.1);
      --border2: rgba(255,255,255,0.18);
      --text: #f0efe9;
      --text2: #a0a09c;
      --text3: #6b6b67;
      --accent: #7fa8d8;
      --accent-bg: #1a2535;
      --green: #97c459;
      --green-bg: #173404;
      --amber: #ef9f27;
      --amber-bg: #412402;
      --red: #f09595;
      --red-bg: #501313;
      --purple: #afa9ec;
      --purple-bg: #26215c;
      --teal: #5dcaa5;
      --teal-bg: #04342c;
    }
  }

  body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
    background: var(--bg);
    color: var(--text);
    font-size: 14px;
    line-height: 1.6;
  }

  .layout { display: flex; min-height: 100vh; }

  /* Sidebar */
  .sidebar {
    width: 220px;
    min-width: 220px;
    background: var(--surface);
    border-right: 0.5px solid var(--border);
    padding: 0;
    position: fixed;
    top: 0; left: 0; bottom: 0;
    overflow-y: auto;
    z-index: 100;
  }
  .sidebar-header {
    padding: 20px 16px 12px;
    border-bottom: 0.5px solid var(--border);
  }
  .sidebar-header h1 {
    font-size: 13px;
    font-weight: 500;
    color: var(--text);
    letter-spacing: 0.01em;
  }
  .sidebar-header p {
    font-size: 11px;
    color: var(--text2);
    margin-top: 2px;
  }
  .trip-dates {
    display: inline-block;
    margin-top: 8px;
    background: var(--accent-bg);
    color: var(--accent);
    font-size: 11px;
    padding: 3px 8px;
    border-radius: 4px;
    font-weight: 500;
  }
  .nav-section {
    padding: 12px 8px 4px;
  }
  .nav-label {
    font-size: 10px;
    font-weight: 500;
    color: var(--text3);
    letter-spacing: 0.08em;
    text-transform: uppercase;
    padding: 0 8px;
    margin-bottom: 4px;
  }
  .nav-item {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 7px 8px;
    border-radius: var(--radius);
    cursor: pointer;
    color: var(--text2);
    font-size: 13px;
    transition: background 0.1s;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
  }
  .nav-item:hover { background: var(--surface2); color: var(--text); }
  .nav-item.active { background: var(--accent-bg); color: var(--accent); }
  .nav-item i { font-size: 16px; width: 18px; text-align: center; }
  .nav-badge {
    margin-left: auto;
    background: var(--surface2);
    color: var(--text3);
    font-size: 10px;
    padding: 1px 6px;
    border-radius: 10px;
  }

  /* Main content */
  .main {
    margin-left: 220px;
    flex: 1;
    padding: 0;
  }

  /* Page header */
  .page-header {
    padding: 28px 32px 20px;
    border-bottom: 0.5px solid var(--border);
    background: var(--surface);
  }
  .page-title {
    font-size: 20px;
    font-weight: 500;
    color: var(--text);
  }
  .page-subtitle {
    font-size: 13px;
    color: var(--text2);
    margin-top: 3px;
  }

  /* Pages */
  .page { display: none; padding: 24px 32px; }
  .page.active { display: block; }

  /* Stat cards */
  .stat-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(140px, 1fr));
    gap: 10px;
    margin-bottom: 24px;
  }
  .stat-card {
    background: var(--surface2);
    border-radius: var(--radius);
    padding: 14px 16px;
  }
  .stat-label {
    font-size: 11px;
    color: var(--text2);
    font-weight: 500;
    margin-bottom: 4px;
  }
  .stat-value {
    font-size: 22px;
    font-weight: 500;
    color: var(--text);
    line-height: 1.2;
  }
  .stat-sub {
    font-size: 11px;
    color: var(--text3);
    margin-top: 2px;
  }

  /* Cards */
  .card {
    background: var(--surface);
    border: 0.5px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 16px 20px;
    margin-bottom: 16px;
  }
  .card-title {
    font-size: 13px;
    font-weight: 500;
    color: var(--text);
    margin-bottom: 12px;
    display: flex;
    align-items: center;
    gap: 8px;
  }
  .card-title i { font-size: 15px; color: var(--text2); }

  /* Timeline */
  .timeline { }
  .tl-item {
    display: flex;
    gap: 12px;
    padding: 8px 0;
    border-bottom: 0.5px solid var(--border);
  }
  .tl-item:last-child { border-bottom: none; }
  .tl-date {
    min-width: 80px;
    font-size: 12px;
    color: var(--text2);
    padding-top: 1px;
  }
  .tl-date strong {
    display: block;
    color: var(--text);
    font-size: 12px;
    font-weight: 500;
  }
  .tl-dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    margin-top: 5px;
    flex-shrink: 0;
  }
  .dot-travel { background: var(--amber); }
  .dot-stay { background: var(--accent); }
  .dot-event { background: var(--green); }
  .tl-content { flex: 1; }
  .tl-title { font-size: 13px; color: var(--text); font-weight: 500; }
  .tl-detail { font-size: 12px; color: var(--text2); margin-top: 1px; }

  /* Badge */
  .badge {
    display: inline-block;
    font-size: 11px;
    padding: 2px 8px;
    border-radius: 4px;
    font-weight: 500;
    margin-left: 6px;
  }
  .badge-travel { background: var(--amber-bg); color: var(--amber); }
  .badge-stay { background: var(--accent-bg); color: var(--accent); }
  .badge-event { background: var(--green-bg); color: var(--green); }
  .badge-warn { background: var(--red-bg); color: var(--red); }
  .badge-purple { background: var(--purple-bg); color: var(--purple); }
  .badge-teal { background: var(--teal-bg); color: var(--teal); }

  /* Route map strip */
  .route-strip {
    display: flex;
    align-items: center;
    gap: 0;
    padding: 16px 0;
    overflow-x: auto;
  }
  .route-city {
    display: flex;
    flex-direction: column;
    align-items: center;
    min-width: 80px;
  }
  .route-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    background: var(--accent-bg);
    border: 1.5px solid var(--accent);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 11px;
    font-weight: 500;
    color: var(--accent);
    margin-bottom: 6px;
  }
  .route-circle.special { background: var(--green-bg); border-color: var(--green); color: var(--green); }
  .route-city-name { font-size: 11px; color: var(--text); font-weight: 500; text-align: center; }
  .route-city-dates { font-size: 10px; color: var(--text2); text-align: center; }
  .route-arrow {
    flex: 1;
    min-width: 24px;
    height: 1px;
    background: var(--border2);
    position: relative;
    margin-bottom: 22px;
  }
  .route-arrow::after {
    content: '';
    position: absolute;
    right: -1px;
    top: -3px;
    width: 6px;
    height: 6px;
    border-top: 1px solid var(--border2);
    border-right: 1px solid var(--border2);
    transform: rotate(45deg);
  }
  .route-arrow span {
    position: absolute;
    top: -16px;
    left: 50%;
    transform: translateX(-50%);
    font-size: 10px;
    color: var(--text3);
    white-space: nowrap;
  }

  /* Table */
  .data-table { width: 100%; border-collapse: collapse; font-size: 13px; }
  .data-table th {
    text-align: left;
    padding: 8px 12px;
    font-size: 11px;
    font-weight: 500;
    color: var(--text2);
    border-bottom: 0.5px solid var(--border);
    background: var(--surface2);
  }
  .data-table td {
    padding: 10px 12px;
    border-bottom: 0.5px solid var(--border);
    color: var(--text);
    vertical-align: top;
  }
  .data-table tr:last-child td { border-bottom: none; }
  .data-table tr:hover td { background: var(--surface2); }

  /* Progress bar */
  .progress-bar {
    height: 6px;
    background: var(--surface2);
    border-radius: 3px;
    overflow: hidden;
    margin-top: 6px;
  }
  .progress-fill {
    height: 100%;
    border-radius: 3px;
    background: var(--accent);
  }
  .progress-fill.green { background: var(--green); }
  .progress-fill.amber { background: var(--amber); }
  .progress-fill.red { background: var(--red); }

  /* Checklist */
  .checklist { list-style: none; }
  .checklist li {
    display: flex;
    align-items: flex-start;
    gap: 10px;
    padding: 8px 0;
    border-bottom: 0.5px solid var(--border);
    font-size: 13px;
    color: var(--text);
  }
  .checklist li:last-child { border-bottom: none; }
  .checklist li.done { color: var(--text3); text-decoration: line-through; }
  .check-box {
    width: 16px;
    height: 16px;
    border: 1px solid var(--border2);
    border-radius: 3px;
    flex-shrink: 0;
    margin-top: 1px;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
  }
  .check-box.checked { background: var(--accent); border-color: var(--accent); }
  .check-box.checked::after { content: '✓'; color: white; font-size: 10px; }

  /* Grid 2col */
  .grid-2 { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; }
  .grid-3 { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 16px; }

  /* People */
  .people-row {
    display: flex;
    gap: 12px;
    flex-wrap: wrap;
    margin-bottom: 16px;
  }
  .person-chip {
    display: flex;
    align-items: center;
    gap: 8px;
    background: var(--surface2);
    border-radius: 20px;
    padding: 6px 12px 6px 6px;
  }
  .avatar {
    width: 28px;
    height: 28px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 11px;
    font-weight: 500;
  }
  .person-chip-name { font-size: 12px; color: var(--text); font-weight: 500; }
  .person-chip-note { font-size: 11px; color: var(--text2); }

  /* Budget */
  .budget-category {
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 10px 0;
    border-bottom: 0.5px solid var(--border);
  }
  .budget-category:last-child { border-bottom: none; }
  .budget-cat-label { flex: 1; font-size: 13px; color: var(--text); }
  .budget-cat-amount { font-size: 13px; font-weight: 500; color: var(--text); min-width: 80px; text-align: right; }
  .budget-cat-bar { flex: 2; }

  /* Attraction card */
  .attraction-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
    gap: 12px;
  }
  .attraction-card {
    background: var(--surface);
    border: 0.5px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 14px;
  }
  .attraction-card-city {
    font-size: 10px;
    font-weight: 500;
    color: var(--text3);
    text-transform: uppercase;
    letter-spacing: 0.05em;
    margin-bottom: 4px;
  }
  .attraction-card-name {
    font-size: 13px;
    font-weight: 500;
    color: var(--text);
    margin-bottom: 6px;
  }
  .attraction-card-note {
    font-size: 11px;
    color: var(--text2);
    line-height: 1.5;
  }

  /* Empty state */
  .empty-state {
    text-align: center;
    padding: 40px 20px;
    color: var(--text3);
  }
  .empty-state i { font-size: 32px; margin-bottom: 8px; display: block; }
  .empty-state p { font-size: 13px; }

  /* Section title */
  .section-title {
    font-size: 12px;
    font-weight: 500;
    color: var(--text2);
    text-transform: uppercase;
    letter-spacing: 0.06em;
    margin: 24px 0 12px;
  }
  .section-title:first-child { margin-top: 0; }

  /* Alert */
  .alert {
    display: flex;
    gap: 10px;
    padding: 12px 14px;
    border-radius: var(--radius);
    font-size: 13px;
    margin-bottom: 12px;
    align-items: flex-start;
  }
  .alert-warn { background: var(--amber-bg); color: var(--amber); }
  .alert-info { background: var(--accent-bg); color: var(--accent); }
  .alert-success { background: var(--green-bg); color: var(--green); }
  .alert i { font-size: 16px; flex-shrink: 0; margin-top: 1px; }

  /* Photo tag */
  .photo-tag {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: var(--purple-bg);
    color: var(--purple);
    font-size: 11px;
    padding: 3px 8px;
    border-radius: 4px;
    font-weight: 500;
    margin: 2px;
  }

  /* Hotel card */
  .hotel-card {
    background: var(--surface);
    border: 0.5px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 14px 16px;
    margin-bottom: 10px;
    display: flex;
    gap: 14px;
    align-items: flex-start;
  }
  .hotel-icon {
    width: 36px;
    height: 36px;
    border-radius: var(--radius);
    background: var(--teal-bg);
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
  }
  .hotel-icon i { font-size: 18px; color: var(--teal); }
  .hotel-info { flex: 1; }
  .hotel-name { font-size: 13px; font-weight: 500; color: var(--text); }
  .hotel-city { font-size: 12px; color: var(--text2); margin-top: 1px; }
  .hotel-dates { font-size: 11px; color: var(--text3); margin-top: 4px; }
  .hotel-status { font-size: 11px; }

  @media (max-width: 768px) {
    .sidebar { width: 100%; position: relative; height: auto; }
    .main { margin-left: 0; }
    .grid-2, .grid-3 { grid-template-columns: 1fr; }
  }
</style>
</head>
<body>
<h2 class="sr-only" style="position:absolute;width:1px;height:1px;overflow:hidden;clip:rect(0,0,0,0);">California Graduation Trip 2026 — Travel dashboard with overview, itinerary, attractions, hotels, budget and task list.</h2>

<div class="layout">

<!-- Sidebar -->
<nav class="sidebar" role="navigation">
  <div class="sidebar-header">
    <h1>🎓 Graduation Trip</h1>
    <p>California · 2026</p>
    <span class="trip-dates">May 29 – Jun 13</span>
  </div>

  <div class="nav-section">
    <div class="nav-label">Overview</div>
    <button class="nav-item active" onclick="showPage('overview')">
      <i class="ti ti-layout-dashboard" aria-hidden="true"></i> Dashboard
    </button>
    <button class="nav-item" onclick="showPage('itinerary')">
      <i class="ti ti-calendar" aria-hidden="true"></i> Itinerary
      <span class="nav-badge">14d</span>
    </button>
    <button class="nav-item" onclick="showPage('route')">
      <i class="ti ti-map-2" aria-hidden="true"></i> Route Planning
    </button>
  </div>

  <div class="nav-section">
    <div class="nav-label">Destinations</div>
    <button class="nav-item" onclick="showPage('attractions')">
      <i class="ti ti-star" aria-hidden="true"></i> Attractions
    </button>
    <button class="nav-item" onclick="showPage('hotels')">
      <i class="ti ti-bed" aria-hidden="true"></i> Hotels & Airbnb
    </button>
    <button class="nav-item" onclick="showPage('restaurants')">
      <i class="ti ti-tools-kitchen-2" aria-hidden="true"></i> Restaurants
    </button>
  </div>

  <div class="nav-section">
    <div class="nav-label">Planning</div>
    <button class="nav-item" onclick="showPage('reservations')">
      <i class="ti ti-ticket" aria-hidden="true"></i> Reservations
    </button>
    <button class="nav-item" onclick="showPage('maps')">
      <i class="ti ti-map-pin" aria-hidden="true"></i> Google Maps
    </button>
    <button class="nav-item" onclick="showPage('photography')">
      <i class="ti ti-camera" aria-hidden="true"></i> Photography
    </button>
    <button class="nav-item" onclick="showPage('outfits')">
      <i class="ti ti-hanger" aria-hidden="true"></i> Outfit Planning
    </button>
  </div>

  <div class="nav-section">
    <div class="nav-label">Finance & Tasks</div>
    <button class="nav-item" onclick="showPage('budget')">
      <i class="ti ti-coin" aria-hidden="true"></i> Budget Tracker
    </button>
    <button class="nav-item" onclick="showPage('tasks')">
      <i class="ti ti-checkbox" aria-hidden="true"></i> Task List
    </button>
  </div>
</nav>

<!-- Main -->
<main class="main">

<!-- Page: Dashboard Overview -->
<div id="page-overview" class="page active">
  <div class="page-header">
    <div class="page-title">California Graduation Trip</div>
    <div class="page-subtitle">May 29 – June 13, 2026 · SD → LA → Yosemite → SF → Hwy 1 → Santa Barbara</div>
  </div>
  <div style="padding: 24px 32px;">

    <div class="stat-grid">
